// Определяем тему по номеру недели
const WEEKLY_TOPICS = [
  ['pushup_invest_1', 'myth_1'],
  ['trucker_1', 'edu_dca'],
  ['pushup_invest_2', 'edu_etf'],
  ['trucker_2', 'myth_2'],
  ['pushup_invest_3', 'by_tax'],
  ['trucker_3', 'edu_compound'],
  ['myth_3', 'by_broker'],
];

const now = new Date();
const weekNum = Math.floor((now - new Date(now.getFullYear(), 0, 1)) / (7 * 24 * 60 * 60 * 1000));
const weekTopics = WEEKLY_TOPICS[weekNum % WEEKLY_TOPICS.length];

// Понедельник = индекс 0, Четверг = индекс 1
const dayOfWeek = now.getDay(); // 1=Mon, 4=Thu
const topicIdx = dayOfWeek === 1 ? 0 : 1;
const topicId = weekTopics[topicIdx];

// Дата старта челенджа
const challengeStart = new Date('2025-10-25');
const dayNumber = Math.floor((now - challengeStart) / (24 * 60 * 60 * 1000)) + 1;
const pushupCount = 10 + (dayNumber - 1);

return [{
  json: {
    topic_id: topicId,
    day_number: dayNumber,
    pushup_count: pushupCount,
    generated_date: now.toISOString().split('T')[0]
  }
}];
